##########
# Problem:
# Design and write code for a generic stack with the following operations
# isEmpty(): tests whether a stack is empty
# push(): add an element to the stack
# pop(): returns the element most recently added that has not yet been returned and removes it from the stack
# top(): return an element which was most recently added and has not yet been returned. However it is not removed from the stack
##########

##########
# The following stack class is based on the stack discussed in the lecture.
# The only difference is that it uses a list instead of a node.
# The methods which are different from lecture are:
# push
# pop
# top
##########


class Stack:

    # Initializing the stack.
    # Use a python list instead of a stack in a stack to make life easier.
    def __init__(self):
         self.stack = []

    # Pushes a specified element onto the top of the stack.
    def push(self, element):
          self.stack.append(element)

    # Removes and returns the element most recently added that has not yet been returned.
    def pop(self):
          if self.isEmpty():
              return None
          else:
              return self.stack.pop(len(self.stack) - 1)

    # Returns the element which was most recently added and has not yet been returned. However it is not removed from the stack.
    def top(self):
          if self.isEmpty():
              return None
          else:
              return self.stack[len(self.stack) - 1]

    # Tests whether a stack is empty
    def isEmpty(self):
         return self.stack == []

