type dpllParams struct {
	Formula          string // input formula string
	Verbosity        int    // level of debug output
	Parallel         int    // degree of parallelism
	ParallelTime     int    // time in sec we wait before we kill a thread when run in parallel
}

var (
	dpllP         *dpllParams
	gotFormula    bool // true if a formula was found on the command line
	gotVerbosity  bool // true if -v found on command line
	gotParallel   bool // true if -p found on command line
	gotParallelT  bool // true if -t found on command line
	gotHelp       bool // true if -? found on command line
	dpllStartTime time.Time
)

// dpllSat returns true or false to denote satisfiability, and the
// solution, if satisfiable.
func dpllSat(formula string, verbose int) (bool, []string) {

	// we start with a time stamp to see how long the program runs.
	dpllStartTime = time.Now()

	// we'll use this heap to keep track of the partial satisfying
	// truth assignments we get during the procedure.
	heapOfPartials := newHeap()

	// initialize the global set of clauses
	s.SetClauses(s.ParseCNF(formula))

	// we want the global partial satisfying truth
	// assignments to start as the empty truth assignment.
	initTruth := s.NewSet()
	heapOfPartials.InitPartials(initTruth)

	// here's the first partial truth assignment that we will push
	// onto the heap to start the whole process.
	firstPartial := s.NewSet()
	firstPartial.Add(s.NewLiteral(1))

	// push the partial satisfying truth assignment into the
	// priority queue.
	heapOfPartials.PushPartials(firstPartial)

	// here's a channel that will carry a partial truth assignment
	// from the dpllSolver function.
	partial := make(chan s.SetOfLiterals)

	// here's a channel that will carry from the dpllSolver function
	// that contains any variables that we must add to the truth
	// assignment because the CNF formula is unsatisfiable. In other
	// words, the value of a literal is the same in every partial
	// truth set that was popped from the heap and then passed to
	// dpllSolver.
	trueSet := make(chan s.NewSetOfLiterals) // channel to carry the literals

	// here's the truth set that dpllSat will return once dpll has run.
	partialsAT := make([]s.NewSetOfLiterals, 0, 1)

	// here's the set of literals that dpll had to add to any partial
	// satisfying truth assignment because the CNF formula was
	// unsatifiable.
	trueLiteralsT := make(s.NewSetOfLiterals, 0, 1)

	// now we launch a number of dpll threads equal to the number of
	// variables in the formula. This is an arbitrary choice.
	for _, variable := range s.SetOfVars(formula) {
		go dpllSolver(variable, heapOfPartials, partial, trueSet)
	}

	// keep running through the dpll threads until all of the truth
	// assignments are popped from the heap.
	for len(heapOfPartials) != 0 {
		p := heapOfPartials.PopPartials()

		// here's an easy way to count the amount of work that dpll
		// does without printing anything out to the terminal.
		if len(heapOfPartials) % 500000 == 0 {
			println("\t\tPartial satisfying assignment =", heapOfPartials[len(heapOfPartials)-1].String())
		}

		select {
		case v := <-partial:
			heapOfPartials.PushPartials(v)
			if len(heapOfPartials) % 100 == 0 {
				if gotVerbosity > 0 {
					println("\t\t\tHeapOfPartials len =", len(heapOfPartials), "Last =", heapOfPartials[len(heapOfPartials)-1], "Time =", time.Since(dpllStartTime))
				}
			}
		case v := <-trueSet:
			trueLiteralsT = append(trueLiteralsT, v)
			if gotVerbosity > 0 {
				println("\t\t\t\tTrue Literal =", v)
			}
			continue
		default:
			// push into the heap the best truth assignment we found for
			// the CNF formula. By "best," I mean the one with the lowest
			// numerical value.
			lowest := p[0]
			for _, partial := range p[1:] {
				if partial.Numeric() < lowest.Numeric() {
					lowest = partial
				}
			}
			// and here we push our best partial satisfying truth assignment
			// back onto the heap.
			heapOfPartials.PushPartials(lowest)
		}
	}

	// at this point, when you're not running in parallel, all of the partial truth assignments have been exhausted.
	// so we'll copy the channels to truth assignments to a slice of truth assignments.
	for i := 0; i < len(partial); i++ {
		partialsAT[i] = (<-partial)
	}

	// print out the partial satisfying truth assignments sorted numerically
	if gotVerbosity > 0 {
		println("\tpartiallySatisfying truth assignments")
		for i := 0; i < len(partialsAT); i++ {
			println("\t\t", partialsAT[i].String())
		}
	}

	// combine all of the partial satisfying truth assignments and add them together
	// to get a single truth assignment.
	var fullTruthAssignment s.SetOfLiterals = s.NewSet()
	for _, partial := range partialsAT {
		fullTruthAssignment = fullTruthAssignment.Union(partial)
	}

	// add to the full truth assignment the truth value for any
	// literals that we know are true because the formula was
	// unsatisfiable.
	trueLiteralsT = s.SetOfLiterals(trueLiteralsT).Difference(trueLiteralsT.UnSAT(fullTruthAssignment)) // remove those literals from any literals that are known to be true on account of the formula being unsatifiable
	fullTruthAssignment = append(fullTruthAssignment, trueLiteralsT...)                               // make sure the value of all literals that we know to be true are present

	// print out what we think the full truth assignment is...
	if gotVerbosity > 0 {
		println("\t\tfullTruthAssignment =", fullTruthAssignment.String())
	}

	// print out the full truth assignment again sorted numerically
	if gotVerbosity > 0 {
		printTruthAssign(fullTruthAssignment)
	}

	// print out any literals that we know are true because the
	// formula is unsatifiable to know what to use to make our
	// input consistent to other problem solving algorithms.
	if gotVerbosity > 0 {
		println("\t\ttrueLiteralsT", trueLiteralsT)
	}

	// return the full truth assignment and the solution, if there is one.
	return len(trueLiteralsT) < 1 && fullTruthAssignment.UnSAT(fullTruthAssignment).Num() < 1, fullTruthAssignment.SAT()
}

// printTruthAssign prints out a given truth assignment, t, sorted
// numerically.
func printTruthAssign(t s.SetOfLiterals, sortIt bool) {
	var vars = t.Vars().Sorted()

	if gotVerbosity > 0 {
		var result = make([]string, 0, len(vars))
		for _, x := range vars {
			result = append(result, x.String())
		}
		sort.Strings(result)

		println("\t\t\tFull solution for truth assignment:")
		print("\t\t\t\t")
		for _, item := range result {
			fmt.Println(item, " ", end="")
		}
		println("")
	}
}

