class SqlQueryMapperSpek : Spek({

    describe("SqlQueryMapper") {
        var result: SqlQueryMapper<String> = null
        val connection = JDBCDatabase.connect("jdbc:h2:mem:db1;DB_CLOSE_DELAY=-1", "sa", "")

        beforeEachTest {
            connection.use { it.executeUpdate("CREATE TABLE foo(bar VARCHAR(32))") }
        }

        given("a resultMapper") {
            beforeEachTest {
                connection.use { it.executeUpdate("INSERT INTO foo(bar) VALUES('foo')") }
            }

            on("mapping scalar result") {
                beforeEachTest {
                    result = SqlQueryMapper.scalar(connection.createQuery("SELECT bar FROM foo WHERE bar = :bar", mapOf("bar" to "foo")))
                }
                it("should be the mapped row") {
                    result!!.queryAndMap().verify().isEqualTo("foo")
                }
            }

            on("checking if there are any rows") {
                beforeEachTest {
                    result = SqlQueryMapper.empty(connection.createEmptyQuery("SELECT bar FROM foo WHERE bar = :bar", mapOf("bar" to "foo")))
                }
                it("should indicate if there are any rows") {
                    result!!.queryAndMap().verify().isTrue()
                }
                it("should be reusable after first invocation") {
                    result!!.queryAndMap().verify().isTrue()
                }
            }

            on("collecting results") {
                val resultSet = emptyList<String>()
                beforeEachTest {
                    result = SqlQueryMapper.scalar(connection.createEmptyQuery("SELECT bar FROM foo WHERE bar = :bar", mapOf("bar" to "foo")))
                }
                it("should collect results") {
                    result!!.queryAndMap().verify().isEqualTo(listOf("foo"))
                }
                it("should be reusable after first invocation") {
                    result!!.queryAndMap().verify().isEqualTo(listOf("foo"))
                }
            }
        }
    }
})

