import S3  from 'aws-sdk/clients/s3'; 

import { Injectable } from '@angular/core';
import { HttpClient } from '@angular/common/http';
import { map, catchError } from 'rxjs/operators';
import { Observable, observable, empty, throwError } from 'rxjs';

import { FileResult, ImageUploadComponent } from '../image-upload/image-upload.component';

import {
  StorageService,
  STORAGE_KEY,
} from '../services/storage.service';

import { UserPreferencesService } from '../services/user-preferences.service';

import ENV from '../environments/environment';

@Injectable()
export class UploadService {

  // s3Config - this holds the configuration for the S3 Service
  // used by putObject
  s3Config: S3.Types.ClientConfiguration;
  // s3 - this holds the reference to the S3 Service itself
  s3: S3;
  // imageUpload - this holds the reference to the Image Upload Component so we can interact with it
  imageUpload: ImageUploadComponent
  // files - this is a list of FileResults uploaded to S3 and stored in our S3 Bucket
  files: Array<FileResult> = [];

  constructor(private http: HttpClient, private storageService: StorageService, private userPreferencesService: UserPreferencesService) {
    // Get our configuration for S3 so we put an object into our S3 bucket
    this.s3Config = {
      accessKeyId: ENV.AMAZON.S3.ACCESS_KEY_ID,
      secretAccessKey: ENV.AMAZON.S3.SECRET_ACCESS_KEY,
      params: { Bucket: ENV.AMAZON.S3.BUCKET },
      region: ENV.AMAZON.S3.REGION
    };
    // Create an Instantiation of the Amazon S3 Service
    this.s3 = new S3(this.s3Config);
    // When we get the component, save it so we can interact with it
    // See this.onAdd() for how we call functions on the image upload
    this.imageUpload.subscribe(this.onAdd());
    // When this component subscribes call this.onSubscribe()
    this.storageService.subscribe(this.onSubscribe());
  }

  // onSubscribe is called when we subscribe to the Storage Service
  onSubscribe(): (files: FileResult[]) => void {
    return (files: FileResult[]) => this.files = files;
  }

  // onAdd is called when we subscribe to the ImageUploadComponent to interact with it and upload files
  onAdd(): (fileUpload: ImageUploadComponent) => void {
    return (imageUpload: ImageUploadComponent) => this.imageUpload = imageUpload;
  }

  // getFiles() is called to return the list of FileResults
  // used when saving this information to local user data
  getFiles() {
    return this.files;
  }

  // putObject() will upload an object from an S3 file location and a put object configuration
  // to an S3 Bucket
  putObject(location: string, config: S3.Types.PutObjectRequest) {
    const params = {
      ...config,
      Body: require('stream').Readable.from(new Buffer('')),
      Key: this.makeKey(location),
    };
    return new Observable((observer) => {
      const request = this.s3.upload(config, (err, data) => {
        if (err) {
          observer.error(err);
        } else {
          observer.next(data);
          observer.complete();
        }
      });
      request.on('httpUploadProgress', (progress) => {
        observer.next(progress);
      });
    });
  }

  // makeKey() will take a string and create a string that is a S3 folder name or S3 file name
  makeKey(key: string) {
    return (key.startsWith('s3://')) ? key.slice(5) : key;
  }

  // uploadFile() will call the putObject function defined above to put a file into our S3 Bucket
  uploadFiles(): Observable<Array<S3.Types.ManagedUpload.SendData>> {
    const uploadFileObservable = new Observable( observer => {
        const putObjects: Array<Observable<S3.Types.ManagedUpload.SendData>> = [];
        this.files.forEach(async fileResult => {
          const fileType = fileResult.fileName.split('.').pop();
          const fileKey = "profile/" + (await this.userPreferencesService.getUserData()).userId + '/.jpg';
          const uploadKey = await this.s3.upload({
            Bucket: ENV.AMAZON.S3.BUCKET,
            Key: fileKey,
            Body: fileResult.file,
            ACL: 'public-read',
            ContentType: "image/" + fileType,
          });
          putObjects.push(uploadKey);
        });
        if (putObjects.length > 0) {
          observer.next(putObjects);
        } else {
          observer.next([]);
        }
        observer.complete();
      }
    );
    //return uploadFileObservable.pipe(map(result => console.log(result)));
    return uploadFileObservable;
  }
}

