"""

Find quadruplete pair such pair element sum upto the given target(sum).

Example: input: arr = [4 3 3 4], target = 8. 
output : [0,1,2,3]

"""

# Approach : Two Pointer / Sort Array + Two Sum Algo

arr    =[4,3,7,6,5,3,4]
target = 9

arr.sort()

def find_quadratic(arr,target):
    for i in range(len(arr)):
        left = i
        right = len(arr) - 1
        # Fix first value of i.
        while right > left:
            if arr[left] + arr[right] > target:
                right = right - 1
            elif arr[left] + arr[right] < target:
                left = left + 1
            else:
                return (left,right)
    return (-1,-1)

result = []
for i in range(len(arr)):
    if arr[i] == target:
        print(i)
        result.append(i)
    else:
        first = i
        second , forth = find_quadratic(arr[first+1:],target - arr[first])
        if second == -1 :
            continue
        else:
            result.append(first)
            result.append(second+first+1)
            result.append(forth+ first + 1)
            break

print("The Quadruple pairs: ",result)

