/************************************************************************************************************************
*
*   void DllLoadHelper(void)
*
*       DESCRIPTION:
*           The actual helper function called in main to initialize and load all DLLs
************************************************************************************************************************/
void DllLoadHelper(void)
{
        // initialize dllDebug_t structure
        DllDebugInit();

        FILE *fp = nullptr;
#ifdef UNICODE
        // for Windows Unicode DLL support
        _wfopen_s(&fp, TEXT("DllLoadHelper.config"), TEXT("r"));
#else
        fopen_s(&fp, "DllLoadHelper.config", "r");
#endif
        if(fp != nullptr)
        {
                // Read every line of the file, using fgets
                char buf[_MAX_PATH] = {0};

                while(!feof(fp))
                {
                        char *p = fgets(buf, _MAX_PATH, fp);
                        // Check for comment, EOF or bad lines
                        if((p == nullptr) || (buf[0] == ';') || (buf[0] == '\r') ||
                           (buf[0] == '\n') || (buf[0] == '\0'))
                                continue;

                        // Strip off newline character if any is present
                        STRIP_NEWLINE(buf);

                        // Do not process empty lines
                        if(strlen(buf) == 0)
                                continue;

                        // Do not process commented out lines
                        if(buf[0] == ';')
                                continue;

                        // Do not process whitespace
                        if(isspace(buf[0]))
                                continue;

                        // Check if we need to reset the current working directory to its initial state
                        if(lstrcmpiA("RESET", buf) == 0)
                        {
                                chdir(g_pCWD);
                        }
                        // Call chdir() only if not called within a command string
                        else if(strchr(buf, ':') == nullptr)
                        {
                                // Call chdir() only if not called within a command string
                                if((chdir(buf) != 0) && (g_bIgnoreMissingModules == false))
                                        FATAL_ERROR("%s:  Could not change to directory: %s\n",
                                                    __FUNCTION__, buf);
                        }
                        // otherwise execute command string in the context of the
                        // current working directory
                        else
                        {
#ifdef UNICODE
#ifdef _MSC_VER       //< Windows Visual C++
                                wmain(0, NULL, NULL);//< must call wmain() for Windows 7/Visual C++ to change current working directory
#else
                                wmain(0, nullptr, nullptr);//< must call wmain() for Windows 7/Visual C++ to change current working directory
#endif
#else
                                main(0, nullptr, nullptr);//< call main()
#endif
                        }

                        // Reset the buffer for loop to read next line of config file
                        memset(buf, 0, _MAX_PATH);
                }
        }
        else
        {
                FATAL_ERROR("%s:  Could not open DllLoadHelper.config\n", __FUNCTION__);
        }

        // Close file handle
        fclose(fp);

#ifdef UNICODE
        // Get the current working directory only if it was originally a
