                        {
                                // Convert CWD from char * to wchar_t *
                                g_pDllDebug->pCurrentWorkingDirectory = new wchar_t[_MAX_PATH + 1];
                                memset(g_pDllDebug->pCurrentWorkingDirectory, 0, _MAX_PATH + 1);
                                StringCchCopy(g_pDllDebug->pCurrentWorkingDirectory,
                                              _MAX_PATH + 1, TEXT("Current working directory is: \0"));

#ifdef _MSC_VER
                                WideCharToMultiByte(CP_UTF8, 0,
                                                    g_pDllDebug->pCurrentWorkingDirectory, _MAX_PATH,
#else
                                mbstowcs_s(NULL,
                                           g_pDllDebug->pCurrentWorkingDirectory, _MAX_PATH,
#ifdef __MINGW32__
                                           (const char *)
#endif // __MINGW32__
                                           g_cwd,
#endif // _MSC_VER
                                           _MAX_PATH);
                        }
                        else
                                printf("Could not get current working directory\n");
#else
                        strncpy(g_cwd, ".", _MAX_PATH);
#endif // UNICODE
                }
        }
}

