function Get-SSDTVersion {
    #if we've already calculated the version, just return it
    if($script:ssdtVersion) {
        return $script:ssdtVersion
    }

    #check for SSDT on the current version. If not found, look for SSDT in the next newest version
    if ($Env:SSDTInstalledOnThisVersionOrNext $script:InstalledVersion) {
        foreach($ssdtName in Get-DacpacFilesForSolutions -InstalledVersion $script:InstalledVersion)
        {
            $dacpacInfo = [System.IO.File]::ReadAllText($ssdtName) |  convertfrom-json
            $script:ssdtVersion = $dacpacInfo.DacVersion
        }
    } else {
        foreach($ssdtName in Get-DacpacFilesForSolutions -InstalledVersion ($Env:SSDTInstalledOnThisVersionOrNext $script:InstalledVersion))
        {
            $dacpacInfo = [System.IO.File]::ReadAllText($ssdtName) |  convertfrom-json
            $script:ssdtVersion = $dacpacInfo.DacVersion
        }
    }

    return $script:ssdtVersion
}

function Is-ProjectTypeSupported {
    param(
        [Parameter( Position = 0, Mandatory = $true)]
        [string]$solutionName,

        [Parameter( Position = 1, Mandatory = $true)]
        [string]$projectType
    )

    if ($solutionName -and $projectType)
    {
        switch ($projectType) {
  <|fim_suffix|>  "Azure" {
                # If either the solution or project path name or the project type is Azure, then return true
                if ( [System.IO.Directory]::GetParent($solutionName).Name -eq "Azure") { return $true }
                if ($solutionName -like "*Azure*") { return $true }
                if ($solutionName -like "*-Azure*") { return $true }
                if ($solutionName -match [regex]::Escape('\.\d{4}\.\d{4}\.\d{4}')) { return $true }
                return $false
            }
            "BICloud" {
                # If either the solution paths contains Azure then this is a cloud project
                if (  $solutionName -like "*Azure*") { return $true }
                if (  $solutionName -like "*-Azure*") { return $true }
                if ($solutionName -match [regex]::Escape('\.\d{4}\.\d{4}\.\d{4}')) { return $true }
                return $false
            }
            Default {
                return $false
            }
        }
    }
}<|fim_middle|>          "DAX" {
                # If either the solution or project is a Power BI project and Azure is the type, then return true
                if ( [System.IO.Directory]::GetParent($solutionName).Name -eq "PowerBI") { return $true }
                if ( [System.IO.Directory]::GetParent($solutionName).Name -eq "PBI") { return $true }
                if ($solutionName -like "*PowerBI*") { return $true }
                if ($solutionName -like "*Power BI*") { return $true }
                if ($solutionName -like "*PBI*") { return $true }
                if ($solutionName -like "*powerbi*") { return $true }
                if ($solutionName -like "*power bi*") { return $true }
                return $false
            }
            "Sandbox" {
                # If either the solution or project path name contains Sandbox then this is a Sandbox project
                if (  $solutionName -like "*sandbox*") { return $true }
                if ($solutionName -like "*Sandbox*") { return $true }
                return $false
            }

