/* # ==========
			The
		   	*    API-Manager, or amjs
		   	*    as it is known is just like any other
		   	* javascript file.
		   	*   As it is an application and not a module, we do not
		   	* use a define block.
	# =========== */

	/**
	* API Manager
	* amjs - Application Management Javascript
 	*/



	/* # ==========
		   	*    Set a property on window to 
		   	* 	represent the instance of amjs.
		   	*  The app name is defined in amjs_conf.js
	# =========== */

	window[App.name] = {
	};

	/**
	* Module to load on demand. Can be placed in its own file
	* so you can dynamically load modules as needed.
	* 
	* @type {object}
	* @name Mod
	*/

	var Mod = {

		/**
 		* Modules that are already loaded
 		* @type {array}
 		* @name Mod.loaded
 		*/

		loaded: [
		],

		/**
 		* The actual API to fetch remote modules
 		* @type {function}
 		* @name Mod.get
 		*/

		get: function(name, args){

				// Make sure someone didn't attempt to fetch
				// the module by its location.
				if(name.indexOf("/") != -1){
						return;
				}

				var url = name.split("/").join(".");
				if(Mod.loaded[url]){
						return;
				}

				if(Mod.loaded[$.camelCase(name)]){
						return;
				}

				Mod.loaded[$.camelCase(name)] = true;

				if(!App.require){
						return Mod.requireModule(name, Mod.loaded[App.appName+".js"]);
				}

			$.get(App.require, function(txt){
					Mod.requireModule(name, txt);
					App.main();	// We're ready
			}, "script");
		},

		/**
 		* Loads the module into memory
 		* @type {function}
 		* @name Mod.requireModule
 		*/

		requireModule: function(name, script){
				if(!App.require){

			var src = location.protocol + "//" + location.host + "/" + name + ".js";
					script = "document.write('<script src='" + src + "'></scr' + 'ipt>');";
				}

				document.write(script);
				/* Mod.getModule(name); */
		}

		/*
		* The module API
		* @type {object}
		* @name Mod.api
		*/

		/*
		* TODO:  We should consider what type of API we need to be able to
		* 		promote modules.
		* 		As we're talking about remote files, I'm not sure how we 
		* 		would acheive this. The only option I can think of would be to
		* 		have a method to inject a module into the loaded list.
		*
		* 		It's not that we need to inject all that often, but this could 
		* 		give a way to have core parts that were always loaded. 
		*/
	};

	/* # ==========
		   	* 	Make the module accessible
		   	*  and also as a local
		   	*  variable.
		   	*  This allows for the module to be
		   	*  fetched on an as needed basis
		   	*  without having to load it
		   	*  every time.
	# =========== */

	if(App.require){
			window.$require = Mod;
	}
	App.Mod = Mod;


	/* # ==========
	   	* 	Load the bootstrap modules
	   	*  so we don't have to wait on loading
	   	*  the app. It will not be called
	   	*	until the script is loaded. If we have
	   	* the require param set though it will
	   	* be available and we can lazyload modules.
	# =========== */

	Mod.get(App.bootstrap[0]);
	if(App.bootstrap.length > 1){
			Mod.get(App.bootstrap[1]);
	}

	/* # ==========
		* Set the app name on the window object
		* this will allow access to properties via window[App.name]
	# =========== */

	window[App.name].app = App;
